#include <stdio.h>

int main() {
    int age;
    float score;

    printf("Enter your age: ");
    scanf("%d", &age);

    printf("Enter your exam score: ");
    scanf("%f", &score);

    printf("Age: %d, Score: %.2f\n", age, score);
    return 0;
}

