#include <stdio.h>
#define PI 3.14159265

int main() {
    double radius, area;
    printf("Enter radius: ");
    if (scanf("%lf", &radius) == 1) {
        area = PI * radius * radius;
        printf("Area: %.3f\n", area);
    }
    return 0;
}

